class ListNode {
    int val;
    ListNode next;
    ListNode(int x) { val = x; }
}

public ListNode mergeNodesBetweenZeros(ListNode head) {
    ListNode dummy = new ListNode(0);
    dummy.next = head;
    ListNode prev = dummy;
    ListNode curr = head;

    while (curr != null) {
        if (curr.val == 0) {
            int tmpSum = 0;
            while (curr.next != null && curr.next.val != 0) {
                tmpSum += curr.next.val;
                curr = curr.next;
            }
            prev.next = new ListNode(tmpSum);
            prev = prev.next;
            curr = curr.next;
        }
    }

    return dummy.next;
}
```

